import React, { useState } from 'react';
import axios from 'axios';

function AddBookForm({ onBookAdded, api_url }) {
  const [title, setTitle] = useState('');
  const [author, setAuthor] = useState('');
  const [rating, setRating] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      const newBook = {
        title,
        author,
        rating: Number(rating),
        reviews: []
      };
      const response = await axios.post(`${api_url}/books`, newBook);
      onBookAdded(response.data);
      // Clear form
      setTitle('');
      setAuthor('');
      setRating('');
    } catch (error) {
      console.error('Error adding book:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl p-12 mb-12 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-0 right-0 w-40 h-40 opacity-5 transform rotate-45 translate-x-12 -translate-y-12">
        <div className="w-full h-full bg-gradient-to-br from-emerald-400 to-teal-500 rounded-full"></div>
      </div>

      <div className="relative">
        <div className="flex items-center mb-8">
          <div className="w-16 h-16 rounded-2xl bg-gradient-to-r from-emerald-500 to-teal-600 flex items-center justify-center shadow-2xl mr-4">
            <span className="text-2xl">📚</span>
          </div>
          <div>
            <h2 className="text-3xl font-bold text-gray-900">Add New Book</h2>
            <p className="text-gray-600 mt-1">Expand your digital library</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="grid md:grid-cols-2 gap-8">
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-3">
                Book Title
              </label>
              <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full p-4 border-2 border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-all duration-200 font-medium bg-gray-50 focus:bg-white"
                placeholder="Enter the book title"
                required
              />
            </div>

            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-3">
                Author Name
              </label>
              <input
                type="text"
                value={author}
                onChange={(e) => setAuthor(e.target.value)}
                className="w-full p-4 border-2 border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-all duration-200 font-medium bg-gray-50 focus:bg-white"
                placeholder="Enter the author's name"
                required
              />
            </div>
          </div>

          <div className="max-w-md">
            <label className="block text-sm font-semibold text-gray-700 mb-3">
              Initial Rating
            </label>
            <select
              value={rating}
              onChange={(e) => setRating(Number(e.target.value))}
              className="w-full p-4 border-2 border-gray-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 transition-all duration-200 font-medium bg-gray-50 focus:bg-white"
              required
            >
              <option value="">Select a rating</option>
              {[1, 2, 3, 4, 5].map(num => (
                <option key={num} value={num}>
                  {num} Star{num !== 1 ? 's' : ''} {'⭐'.repeat(num)}
                </option>
              ))}
            </select>
          </div>

          <div className="flex justify-center">
            <button
              type="submit"
              disabled={isSubmitting}
              className="inline-flex items-center px-8 py-4 bg-gradient-to-r from-emerald-500 to-teal-600 text-white rounded-xl font-semibold hover:from-emerald-600 hover:to-teal-700 focus:ring-2 focus:ring-emerald-500 focus:ring-offset-2 transition-all duration-200 transform hover:scale-105 shadow-lg hover:shadow-xl disabled:opacity-50 disabled:transform-none"
            >
              {isSubmitting ? (
                <>
                  <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent mr-3"></div>
                  Adding Book...
                </>
              ) : (
                <>
                  <svg className="icon-md mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                  </svg>
                  Add to Library
                </>
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AddBookForm;
